	"golang.org/x/net/html/atom"
	"golang.org/x/net/html/charset"
)

const (
	maxRequestSize = 4 << 10 // 4KB maximum size for incoming request body
	maxBodySize    = 1 << 20 // 1MB maximum size for fetched response body
)

// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// sendJSONError helper to return JSON-formatted error responses
func sendJSONError(ctx *fasthttp.RequestCtx, message string, statusCode int) {
	resp := PreviewResponse{
		Error: message,
	}
	ctx.SetStatusCode(statusCode)
	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err!= nil {
		// Fallback to plain text if JSON encoding fails
		ctx.Error("Failed to encode error response", fasthttp.StatusInternalServerError)
	}
}

// validateURLIP resolves and validates that the URL's hostname points to public non-private IPs
func validateURLIP(parsedURL *url.URL) (net.IP, error) {
	hostname := parsedURL.Hostname()
	if hostname == "" {
		return nil, fmt.Errorf("missing hostname")
	}

	ips, err := net.LookupIP(hostname)
	if err!= nil {
		return nil, fmt.Errorf("failed to resolve hostname: %w", err)
	}

	for _, ip := range ips {
		if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsPrivate() {
			return nil, fmt.Errorf("access to private/loopback addresses is not allowed")
		}
	}

	// Return first valid public IP
	return ips[0], nil
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST method (early return to reduce nesting)
	if!ctx.IsPost() {
		sendJSONError(ctx, "Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	// Limit request body size to prevent large malicious requests
	bodyStream := ctx.Request.BodyStream()
	if bodyStream == nil {
		bodyStream = bytes.NewReader(nil)
	}
	limitReader := io.LimitReader(bodyStream, maxRequestSize)
	var req struct {
		URL string `json:"url"`
	}
	if err := json.NewDecoder(limitReader).Decode(&req); err!= nil {
		sendJSONError(ctx, "Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		sendJSONError(ctx, "URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Prepend http:// if no scheme is present to handle user-friendly URLs
	if!strings.HasPrefix(targetURL, "http://") &&!strings.HasPrefix(targetURL, "https://") {
		targetURL = "http://" + targetURL
	}

	// Validate URL format and scheme
	parsedURL, err := url.Parse(targetURL)
	if err!= nil {
		sendJSONError(ctx, "Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme!= "http" && parsedURL.Scheme!= "https" {
		sendJSONError(ctx, "URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// Validate initial URL IP
	_, err = validateURLIP(parsedURL)
	if err!= nil {
		sendJSONError(ctx, err.Error(), fasthttp.StatusBadRequest)
		return
	}

	// Acquire and release request/response objects from pool
	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.Header.SetMethod(fasthttp.MethodGet)
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	const maxRedirectCounts = 10
	currentURL := targetURL

	// Manual redirect handling with SSRF validation for each redirect
	for redirectCount := 0; redirectCount < maxRedirectCounts; redirectCount++ {
		currentParsedURL, err := url.Parse(currentURL)
		if err!= nil {
			sendJSONError(ctx, "Invalid redirect URL format", fasthttp.StatusBadGateway)
			return
		}

		if currentParsedURL.Scheme!= "http" && currentParsedURL.Scheme!= "https" {
			sendJSONError(ctx, "Redirect URL must use http or https scheme", fasthttp.StatusBadGateway)
			return
		}

		// Validate redirect URL IP
		validIP, err := validateURLIP(currentParsedURL)
		if err!= nil {
			sendJSONError(ctx, err.Error(), fasthttp.StatusBadRequest)
			return
		}

		// Get port with default fallback
		port := currentParsedURL.Port()
		if port == "" {
			if currentParsedURL.Scheme == "http" {
				port = "80"
			} else {
				port = "443"
			}
		}
		addr := net.JoinHostPort(validIP.String(), port)

		// Create per-request client with custom dial to prevent DNS rebinding
		client := &fasthttp.Client{
			Dial: func(_ string) (net.Conn, error) {
				return fasthttp.DialDualStack(addr)
			},
			ReadTimeout:         10 * time.Second,
			WriteTimeout:        10 * time.Second,
			MaxIdleConnDuration: 30 * time.Second,
			MaxConnsPerHost:     10,
		}

		// Update request with current URL and correct Host header
		freq.SetRequestURI(currentURL)
		freq.Header.SetHost(currentParsedURL.Host)

		// Execute request
		err = client.Do(freq, res)
		if err!= nil {
			sendJSONError(ctx, fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
			return
		}

		// Check if we need to follow redirect
		statusCode := res.StatusCode()
		if statusCode < 300 || statusCode >= 400 {
			break
		}

		// Get redirect location
		location := string(res.Header.Peek("Location"))
		if location == "" {
			break
		}

		// Resolve relative redirect URLs
		parsedLocation, err := currentParsedURL.Parse(location)
		if err!= nil {
			sendJSONError(ctx, "Invalid redirect location", fasthttp.StatusBadGateway)
			return
		}
		currentURL = parsedLocation.String()

		// Reset response for next request
		fasthttp.ReleaseResponse(res)
		res = fasthttp.AcquireResponse()
	}

	if res.StatusCode()!= fasthttp.StatusOK {
		sendJSONError(ctx, fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	// Verify response is HTML content
	contentType := string(res.Header.ContentType())
	if!strings.HasPrefix(strings.ToLower(contentType), "text/html") {
		sendJSONError(ctx, "Response is not HTML content", fasthttp.StatusBadGateway)
		return
	}

	// Read up to maxBodySize bytes from response (prevent DoS from large files)
	respBodyStream := res.BodyStream()
	if respBodyStream == nil {
		sendJSONError(ctx, "Empty response body", fasthttp.StatusBadGateway)
		return
	}
	bodyBytes := make([]byte, maxBodySize)
	n, err := io.ReadFull(respBodyStream, bodyBytes)
	if err!= nil && err!= io.ErrUnexpectedEOF && err!= io.EOF {
		sendJSONError(ctx, "Failed to read response body", fasthttp.StatusBadGateway)
		return
	}
	bodyBytes = bodyBytes[:n]

	if len(bodyBytes) == 0 {
		sendJSONError(ctx, "Empty response body", fasthttp.StatusBadGateway)
		return
	}

	// Convert response to UTF-8 handling different encodings
	bodyReader, err := charset.NewReader(bytes.NewReader(bodyBytes), contentType)
