		sendJSONError(ctx, fmt.Sprintf("Failed to decode content encoding: %v", err), fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bodyReader)
	if err!= nil {
		sendJSONError(ctx, fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	// Return successful response
	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}
	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err!= nil {
		sendJSONError(ctx, "Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// parseHTMLPreview extracts title and meta description from HTML with forgiving parsing
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	tokenizer := html.NewTokenizer(r)

	for {
		tt := tokenizer.Next()
		switch tt {
		case html.ErrorToken:
			if tokenizer.Err() == io.EOF {
				// Return trimmed values on end of input
				return strings.TrimSpace(title), strings.TrimSpace(description), nil
			}
			return "", "", tokenizer.Err()

		case html.StartTagToken, html.SelfClosingTagToken:
			tagName, hasAttr := tokenizer.TagName()
			tagAtom := atom.Lookup(tagName)

			switch tagAtom {
			case atom.Title:
				if title == "" { // Only take first occurrence of title tag
					var titleText strings.Builder
					// Collect all text content until closing title tag (handles nested invalid tags)
					for {
						contentTT := tokenizer.Next()
						switch contentTT {
						case html.TextToken:
							titleText.Write(tokenizer.Text())
						case html.EndTagToken:
							endTagName, _ := tokenizer.TagName()
							if atom.Lookup(endTagName) == atom.Title {
								title = titleText.String()
								// Early exit if we already have both required fields
								if description!= "" {
									return strings.TrimSpace(title), strings.TrimSpace(description), nil
								}
								goto endTitleProcessing
							}
						case html.ErrorToken:
							// Premature end of input, return collected content
							title = titleText.String()
							return strings.TrimSpace(title), strings.TrimSpace(description), tokenizer.Err()
						}
					}
				endTitleProcessing:
				}

			case atom.Meta:
				if description == "" && hasAttr { // Only take first description meta tag
					var metaName, metaContent string
					// Iterate through meta tag attributes
					for {
						attrKey, attrVal, moreAttr := tokenizer.TagAttr()
						attrKeyStr := string(attrKey)
						// Case-insensitive attribute matching
						if strings.EqualFold(attrKeyStr, "name") {
							metaName = strings.ToLower(string(attrVal))
						} else if strings.EqualFold(attrKeyStr, "content") {
							metaContent = string(attrVal)
						}
						if!moreAttr {
							break
						}
					}
					if metaName == "description" && metaContent!= "" {
						description = metaContent
						// Early exit if we have both required fields
						if title!= "" {
							return strings.TrimSpace(title), strings.TrimSpace(description), nil
						}
					}
				}

			case atom.Body:
				// Early exit if we already have both fields when reaching body content
				if title!= "" && description!= "" {
					return strings.TrimSpace(title), strings.TrimSpace(description), nil
				}
			}
		}
	}
}

