// PreviewRequest represents the incoming JSON request structure
type PreviewRequest struct {
	URL string `json:"url"`
}

// PreviewResponse represents the outgoing JSON response structure
type PreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST requests
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	// Parse incoming JSON request
	var req PreviewRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.Error(fmt.Sprintf("Invalid request body: %v", err), fasthttp.StatusBadRequest)
		return
	}

	// Validate required URL field
	if req.URL == "" {
		ctx.Error("URL field is required", fasthttp.StatusBadRequest)
		return
	}

	// Acquire reusable request/response objects for outgoing HTTP call
	outReq := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(outReq)
	outResp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(outResp)

	// Configure outgoing request
	outReq.SetRequestURI(req.URL)
	// Set descriptive User-Agent to avoid being blocked by servers
	outReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewFetcher/1.0)")

	// Fetch URL with redirect following, 3 second timeout as required
	err := httpClient.DoRedirects(outReq, outResp, 10)
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	// Verify successful response status
	if outResp.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("URL returned non-success status code: %d", outResp.StatusCode()), fasthttp.StatusInternalServerError)
		return
	}

	// Extract title and description from HTML content
	title, description, err := extractPreview(outResp.Body())
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML content: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	// Prepare and send JSON response
	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json")
	ctx.SetStatusCode(fasthttp.StatusOK)
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error(fmt.Sprintf("Failed to generate response: %v", err), fasthttp.StatusInternalServerError)
		return
	}
}

// extractPreview parses HTML content to extract page title and meta description
func extractPreview(htmlContent []byte) (title, description string, err error) {
	doc, err := html.Parse(bytes.NewReader(htmlContent))
	if err != nil {
		return "", "", err
	}

	var traverseNode func(*html.Node)
	traverseNode = func(n *html.Node) {
		// Look for the <head> element to process relevant tags
		if n.Type == html.ElementNode && n.DataAtom == atom.Head {
			for child := n.FirstChild; child != nil; child = child.NextSibling {
				if child.Type != html.ElementNode {
					continue
				}

				switch child.DataAtom {
				case atom.Title:
					// Extract text content from <title> tag
					if child.FirstChild != nil && child.FirstChild.Type == html.TextNode {
						title = strings.TrimSpace(child.FirstChild.Data)
					}
				case atom.Meta:
					// Check for <meta name="description"> tag (case-insensitive)
					var metaName, metaContent string
					for _, attr := range child.Attr {
						switch strings.ToLower(attr.Key) {
						case "name":
							metaName = strings.ToLower(attr.Val)
						case "content":
							metaContent = attr.Val
						}
					}
					if metaName == "description" {
						description = metaContent
					}
				}
			}
			// No need to traverse further once head is processed
			return
		}

		// Continue traversing child nodes
		for child := n.FirstChild; child != nil; child = child.NextSibling {
			traverseNode(child)
		}
	}

	traverseNode(doc)
	return title, description, nil
}

func main() {
	fmt.Println("URL Preview server starting on :8080...")
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err != nil {
		fmt.Printf("Server failed to start: %v\n", err)
	}
}

