// httpClient is a reusable fasthttp client with optimized settings for URL preview fetching
var httpClient = &fasthttp.Client{
	Dial:                fasthttp.DialDualStack,
	ReadTimeout:         10 * time.Second,
	WriteTimeout:        10 * time.Second,
	MaxIdleConnDuration: 10 * time.Second,
	MaxConnsPerHost:     10,
	MaxResponseBodySize: 1 << 20, // Limit response body to 1MB (sufficient for head section parsing)
