// parseHTMLPreview extracts title and meta description from HTML content.
// It handles case-insensitive attribute matching and collects full text content from title tags.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err!= nil {
		return "", "", err
	}
	// Helper function to extract all text content from a node (handles nested text nodes)
	getTextContent := func(n *html.Node) string {
		var textBuf strings.Builder
		var traverse func(*html.Node)
		traverse = func(node *html.Node) {
			if node.Type == html.TextNode {
				textBuf.WriteString(node.Data)
			}
			for child := node.FirstChild; child!= nil; child = child.NextSibling {
				traverse(child)
			}
		}
		traverse(n)
		return strings.TrimSpace(textBuf.String())
	}
	// Traverse HTML tree to find title and meta description
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		// Early exit if we already have both required fields
		if title!= "" && description!= "" {
			return
		}
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if title == "" {
					title = getTextContent(n)
				}
			case "meta":
				var name, content string
				for _, attr := range n.Attr {
					attrKey := strings.ToLower(attr.Key)
					switch attrKey {
					case "name":
						name = strings.ToLower(attr.Val)
					case "content":
						content = attr.Val
					}
				}
				// Extract standard description meta tag
				if name == "description" && description == "" {
					description = strings.TrimSpace(content)
				}
				// Uncomment below to add Open Graph description as fallback
				// if property == "og:description" && description == "" {
				// 	description = strings.TrimSpace(content)
				// }
			}
		}
		// Recurse into child nodes
		for child := n.FirstChild; child!= nil; child = child.NextSibling {
			traverse(child)
		}
	}
	traverse(doc)
	return title, description, nil
}

