// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// ForbiddenError represents an error for forbidden targets (SSRF prevention)
type ForbiddenError struct {
	Message string
}

func (e *ForbiddenError) Error() string {
	return e.Message
}

var forbiddenIPNets []*net.IPNet

func init() {
	// List of forbidden IP ranges (private, reserved, loopback, etc.) to prevent SSRF
	forbiddenCIDRs := []string{
		// IPv4 ranges
		"10.0.0.0/8",         // Private network
		"172.16.0.0/12",      // Private network
		"192.168.0.0/16",     // Private network
		"127.0.0.0/8",        // Loopback
		"169.254.0.0/16",     // Link-local
		"100.64.0.0/10",      // CGNAT shared space
		"192.0.2.0/24",       // TEST-NET-1 (documentation)
		"198.51.100.0/24",    // TEST-NET-2 (documentation)
		"203.0.113.0/24",     // TEST-NET-3 (documentation)
		"224.0.0.0/4",        // Multicast
		"255.255.255.255/32", // Broadcast
		// IPv6 ranges
		"::1/128",       // Loopback
		"fc00::/7",      // Unique local address
		"fe80::/10",     // Link-local address
		"ff00::/8",      // Multicast
		"2001:db8::/32", // Documentation range
	}

	for _, cidr := range forbiddenCIDRs {
		_, ipNet, err := net.ParseCIDR(cidr)
		if err != nil {
			panic(fmt.Sprintf("invalid CIDR in forbidden list: %s, error: %v", cidr, err))
		}
		forbiddenIPNets = append(forbiddenIPNets, ipNet)
	}
}

// isForbiddenIP checks if the given IP is in the forbidden ranges
func isForbiddenIP(ip net.IP) bool {
	for _, ipNet := range forbiddenIPNets {
		if ipNet.Contains(ip) {
			return true
		}
	}
	return false
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	// Validate request Content-Type is JSON
	contentType := string(ctx.Request.Header.ContentType())
	if !strings.Contains(strings.ToLower(contentType), "application/json") {
		ctx.Error("Content-Type must be application/json", fasthttp.StatusUnsupportedMediaType)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL format and scheme
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// Block URLs containing user credentials (e.g. http://user:pass@example.com)
	if parsedURL.User != nil {
		ctx.Error("URL must not contain user credentials", fasthttp.StatusBadRequest)
		return
	}

	// Create custom dialer with SSRF protection (IP/port validation)
	dialer := &net.Dialer{
		Timeout:   5 * time.Second, // Connection establishment timeout
		KeepAlive: 30 * time.Second,
		Control: func(network, address string, c syscall.RawConn) error {
			// Split address into IP and port
			host, portStr, err := net.SplitHostPort(address)
			if err != nil {
				return err
			}

			// Restrict to standard HTTP/HTTPS ports to prevent port scanning
			port, err := strconv.Atoi(portStr)
			if err != nil {
				return err
			}
			if port != 80 && port != 443 {
				return &ForbiddenError{Message: fmt.Sprintf("port %d is not allowed", port)}
			}

			// Validate IP address is not in forbidden range
			ip := net.ParseIP(host)
			if ip == nil {
				return fmt.Errorf("invalid IP address: %s", host)
			}
			if isForbiddenIP(ip) {
				return &ForbiddenError{Message: fmt.Sprintf("IP %s is forbidden", ip)}
			}

			return nil
		},
	}

	// Configure fasthttp client with timeouts and custom dialer
	client := &fasthttp.Client{
		Dial: func(addr string) (net.Conn, error) {
			return dialer.Dial("tcp", addr)
		},
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	// Enable streaming to avoid loading entire response into memory
	res.StreamBody = true

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	maxRedirectCounts := 10
	if err := client.DoRedirects(freq, res, maxRedirectCounts); err != nil {
		var forbiddenErr *ForbiddenError
		if errors.As(err, &forbiddenErr) {
			// Return generic error for forbidden targets to avoid leaking internal details
			ctx.Error("Failed to fetch URL: invalid target", fasthttp.StatusBadGateway)
		} else {
			ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		}
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	// Validate response is HTML
	respContentType := string(res.Header.ContentType())
	if !strings.HasPrefix(strings.ToLower(respContentType), "text/html") {
		ctx.Error("URL does not return HTML content", fasthttp.StatusBadGateway)
		return
	}

	// Limit response body to 1MB to prevent memory exhaustion (only need <head> section)
	const maxBodySize = 1 << 20 // 1MB
	bodyBytes, err := io.ReadAll(io.LimitReader(res.BodyStream(), maxBodySize))
	if err != nil {
		ctx.Error("Failed to read response body", fasthttp.StatusBadGateway)
		return
	}

	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	return "dummy title", "dummy description", nil
}

