	fetchResp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(fetchResp)

	// Configure upstream request
	fetchReq.SetRequestURI(req.URL)
	fetchReq.Header.SetMethod(fasthttp.MethodGet)
	// Set standard user agent to avoid being blocked by common servers
	fetchReq.Header.Set("User-Agent", "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36")

	// Fetch URL with redirect following (max 10 redirects) and 3 second total timeout
	err := httpClient.DoRedirectsDeadline(fetchReq, fetchResp, 10, time.Now().Add(3*time.Second))
	if err!= nil {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		_ = json.NewEncoder(ctx).Encode(PreviewResponse{Error: fmt.Sprintf("failed to fetch URL: %v", err)})
		return
	}

	// Validate response is HTML
	contentType := string(fetchResp.Header.ContentType())
	if!strings.Contains(strings.ToLower(contentType), "text/html") {
		ctx.SetStatusCode(fasthttp.StatusUnsupportedMediaType)
		_ = json.NewEncoder(ctx).Encode(PreviewResponse{Error: "URL does not return HTML content"})
		return
	}

	// Convert response body to UTF-8 based on detected charset
	reader, err := charset.NewReader(bytes.NewReader(fetchResp.Body()), contentType)
	if err!= nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		_ = json.NewEncoder(ctx).Encode(PreviewResponse{Error: fmt.Sprintf("failed to decode content: %v", err)})
