	if err!= nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		_ = json.NewEncoder(ctx).Encode(PreviewResponse{Error: fmt.Sprintf("failed to parse HTML: %v", err)})
		return
	}

	// Extract metadata
	title, description := extractMetadata(doc)

	// Return successful response
	ctx.SetStatusCode(fasthttp.StatusOK)
	_ = json.NewEncoder(ctx).Encode(PreviewResponse{
		Title:       title,
		Description: description,
	})
}

func main() {
	log.Println("Starting server on :8080")

	// Simple router configuration
	handler := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.SetStatusCode(fasthttp.StatusNotFound)
			ctx.SetContentType("application/json")
			_ = json.NewEncoder(ctx).Encode(map[string]string{"error": "endpoint not found"})
		}
	}

	// Start fasthttp server
	if err := fasthttp.ListenAndServe(":8080", handler); err!= nil {
		log.Fatalf("Failed to start server: %v", err)
	}
}

