package main

import (
	"bytes"
	"encoding/json"
	"fmt"
	"io"
	"net/url"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// sendJSONError sends a JSON response with an error message and status code.
func sendJSONError(ctx *fasthttp.RequestCtx, message string, statusCode int) {
	resp := PreviewResponse{
		Error: message,
	}
	jsonResp, err := json.Marshal(resp)
	if err!= nil {
		// Fallback to plain text if JSON marshaling fails for error response
		ctx.Error("Failed to encode error response", fasthttp.StatusInternalServerError)
		return
	}
	ctx.SetStatusCode(statusCode)
	ctx.SetContentType("application/json; charset=utf-8")
	_, _ = ctx.Write(jsonResp)
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if!ctx.IsPost() {
		sendJSONError(ctx, "Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err!= nil {
		sendJSONError(ctx, "Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		sendJSONError(ctx, "URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL format, host and scheme
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err!= nil {
		sendJSONError(ctx, "Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Host == "" {
		sendJSONError(ctx, "URL must include a valid host", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme!= "http" && parsedURL.Scheme!= "https" {
		sendJSONError(ctx, "URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// Configure fasthttp client with timeouts and limits
	client := &fasthttp.Client{
		Dial:                fasthttp.DialDualStack,
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
		MaxResponseBodySize: 1 << 20, // 1MB limit to prevent large file downloads
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod(fasthttp.MethodGet)
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	maxRedirectCounts := 10
	if err := client.DoRedirects(freq, res, maxRedirectCounts); err!= nil {
		sendJSONError(ctx, fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode()!= fasthttp.StatusOK {
		sendJSONError(ctx, fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	// Verify response is HTML content
	contentType := string(res.Header.ContentType())
	if!strings.HasPrefix(strings.ToLower(contentType), "text/html") {
		sendJSONError(ctx, "URL does not return HTML content", fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		sendJSONError(ctx, "Empty response body", fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err!= nil {
		sendJSONError(ctx, fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusBadGateway)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	jsonResp, err := json.Marshal(resp)
	if err!= nil {
		sendJSONError(ctx, "Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}

	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.SetContentType("application/json; charset=utf-8")
	_, _ = ctx.Write(jsonResp)
}

// parseHTMLPreview extracts title and meta description from HTML content.
// It stops parsing once the head section ends or both title and description are found for efficiency.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	tokenizer := html.NewTokenizer(r)

	for {
		tt := tokenizer.Next()
		switch tt {
		case html.ErrorToken:
			if tokenizer.Err() == io.EOF {
				// End of input, return whatever we've collected
				return title, description, nil
			}
			// Return parsing errors
			return "", "", tokenizer.Err()

		case html.StartTagToken, html.SelfClosingTagToken:
			tagNameBytes, _ := tokenizer.TagName()
			tagName := strings.ToLower(string(tagNameBytes))

			switch tagName {
			case "title":
				// Skip invalid self-closing title tags
				if tt!= html.StartTagToken {
					continue
				}

				// Collect all text content inside the title tag (handles nested elements)
				var titleBuf strings.Builder
				for {
					innerTT := tokenizer.Next()
					if innerTT == html.EndTagToken {
						innerTagNameBytes, _ := tokenizer.TagName()
						innerTagName := strings.ToLower(string(innerTagNameBytes))
						if innerTagName == "title" {
							break
						}
					}

					if innerTT == html.TextToken {
						titleBuf.Write(tokenizer.Text())
					}

					// Exit early if we hit an error while parsing title
					if innerTT == html.ErrorToken {
						break
					}
				}
				title = strings.TrimSpace(titleBuf.String())

			case "meta":
				var nameAttr, contentAttr string
				// Iterate through meta tag attributes
				for {
					attrKey, attrVal, moreAttr := tokenizer.TagAttr()
					attrKeyStr := strings.ToLower(string(attrKey))

					switch attrKeyStr {
					case "name":
						nameAttr = strings.ToLower(string(attrVal))
					case "content":
						contentAttr = string(attrVal)
					}

					if!moreAttr {
						break
					}
				}

				// Capture description if this is the description meta tag
				if nameAttr == "description" {
					description = strings.TrimSpace(contentAttr)
				}

			case "body":
				// Reached body section, no more head elements to parse
				return title, description, nil
			}

		case html.EndTagToken:
			tagNameBytes, _ := tokenizer.TagName()
			tagName := strings.ToLower(string(tagNameBytes))
			if tagName == "head" {
				// Head section ended, stop parsing early
				return title, description, nil
			}
		}

		// Early exit if we have both required fields
		if title!= "" && description!= "" {
			break
		}
	}

	return title, description, nil
}

