// isIPAllowed checks if the given IP is a public, non-restricted IP address.
// It blocks loopback, private, link-local, multicast, and unspecified addresses.
func isIPAllowed(ip net.IP) bool {
	switch {
	case ip.IsLoopback(),
		ip.IsPrivate(),
		ip.IsLinkLocalUnicast(),
		ip.IsLinkLocalMulticast(),
		ip.IsInterfaceLocalMulticast(),
		ip.IsMulticast(),
		ip.IsUnspecified():
		return false
	default:
		return true
	}
}

// customDial is a secure dial implementation that validates ports and IP addresses
// before establishing a connection to prevent SSRF attacks and port scanning.
func customDial(addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err!= nil {
		return nil, fmt.Errorf("invalid address: %w", err)
	}

	// Restrict to standard HTTP/HTTPS ports to prevent arbitrary port scanning
	if port!= "80" && port!= "443" {
		return nil, fmt.Errorf("disallowed port %s: only 80 (HTTP) and 443 (HTTPS) are permitted", port)
	}

	// Resolve host to IP addresses (both IPv4 and IPv6)
	ips, err := net.LookupIP(host)
	if err!= nil {
		return nil, fmt.Errorf("failed to resolve host: %w", err)
	}

	// Filter out restricted IP addresses to prevent SSRF
	var allowedIPs []net.IP
	for _, ip := range ips {
		if isIPAllowed(ip) {
			allowedIPs = append(allowedIPs, ip)
		}
	}

	if len(allowedIPs) == 0 {
		return nil, fmt.Errorf("no public IP addresses available for host %s", host)
	}

	// Try dialing each allowed IP with a timeout to prevent hanging connections
	dialTimeout := 5 * time.Second
	var lastErr error
	for _, ip := range allowedIPs {
		dialAddr := net.JoinHostPort(ip.String(), port)
		conn, err := net.DialTimeout("tcp", dialAddr, dialTimeout)
		if err == nil {
			return conn, nil
		}
		lastErr = err
	}

	return nil, fmt.Errorf("failed to establish connection: %w", lastErr)
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST requests
	if!ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	const maxRequestSize = 1 << 20 // 1MB maximum request body size to prevent DoS
	var req struct {
		URL string `json:"url"`
	}

	// Limit request body size to avoid memory exhaustion from large payloads
	err := json.NewDecoder(io.LimitReader(bytes.NewReader(ctx.Request.Body()), maxRequestSize)).Decode(&req)
	if err!= nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL format and scheme
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err!= nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme!= "http" && parsedURL.Scheme!= "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// Block URLs containing authentication credentials to prevent credential leakage
	if parsedURL.User!= nil {
		ctx.Error("URL must not contain authentication credentials", fasthttp.StatusBadRequest)
		return
	}

	// Configure fasthttp client with security constraints
	client := &fasthttp.Client{
		Dial:                customDial,
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
		MaxResponseBodySize: 1 << 20, // 1MB maximum response size to prevent DoS
	}

	// Acquire and configure request
	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	// Fetch URL with redirect limit
	maxRedirectCounts := 10
	if err := client.DoRedirects(freq, res, maxRedirectCounts); err!= nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	// Validate successful response
	if res.StatusCode()!= fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	// Validate response is HTML to avoid parsing non-HTML content
	contentType := strings.ToLower(string(res.Header.ContentType()))
	if!strings.HasPrefix(contentType, "text/html") &&!strings.HasPrefix(contentType, "application/xhtml+xml") {
		ctx.Error("URL does not return HTML content", fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	// Parse HTML for preview data
	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err!= nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	// Prepare and send response
	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err!= nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
