	bodyReader := bytes.NewReader(httpResp.Body())
	utf8Reader, err := charset.NewReader(bodyReader, contentType)
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		_ = json.NewEncoder(ctx).Encode(PreviewResponse{
			Error: "failed to decode content encoding: " + err.Error(),
		})
		return
	}
	// Parse HTML to extract preview data
	title, description, err := parseHTML(utf8Reader)
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		_ = json.NewEncoder(ctx).Encode(PreviewResponse{
			Error: "failed to parse HTML content: " + err.Error(),
		})
		return
	}
	// Return successful response with extracted data
	ctx.SetStatusCode(fasthttp.StatusOK)
	_ = json.NewEncoder(ctx).Encode(PreviewResponse{
		Title:       title,
		Description: description,
	})
}
