// parseHTMLPreview extracts title and meta description from HTML content,
// handling charset conversion and early termination after the head section.
func parseHTMLPreview(r io.Reader, contentType string) (title, description string, err error) {
	// Convert input to UTF-8 based on detected charset (from Content-Type header or HTML meta tags)
	utf8Reader, err := charset.NewReader(r, contentType)
	if err!= nil {
		return "", "", fmt.Errorf("failed to convert content to UTF-8: %w", err)
	}

	tokenizer := html.NewTokenizer(utf8Reader)
	inTitle := false // Tracks if we're inside the <title> tag

	for {
		tokenType := tokenizer.Next()
		switch tokenType {
		case html.ErrorToken:
			// EOF is acceptable if we reach end of input before closing </head>
			if tokenizer.Err() == io.EOF {
				return strings.TrimSpace(title), strings.TrimSpace(description), nil
			}
			return "", "", fmt.Errorf("HTML parsing error: %w", tokenizer.Err())

		case html.StartTagToken:
			tagName, hasAttr := tokenizer.TagName()
			lowTagName := strings.ToLower(string(tagName))

			if lowTagName == "title" {
				inTitle = true
				continue
			}

			if lowTagName == "meta" && hasAttr {
				if desc, ok := extractDescriptionFromMeta(tokenizer); ok {
					description = desc
				}
			}

		case html.TextToken:
			if inTitle {
				title += string(tokenizer.Text())
			}

		case html.EndTagToken:
			tagName, _ := tokenizer.TagName()
			lowTagName := strings.ToLower(string(tagName))

			if lowTagName == "title" {
				inTitle = false
			} else if lowTagName == "head" {
				// Early exit: no need to parse the body content
				return strings.TrimSpace(title), strings.TrimSpace(description), nil
			}

		case html.SelfClosingTagToken:
			tagName, hasAttr := tokenizer.TagName()
			lowTagName := strings.ToLower(string(tagName))

			if lowTagName == "meta" && hasAttr {
				if desc, ok := extractDescriptionFromMeta(tokenizer); ok {
					description = desc
				}
			}
		}
	}
}

// extractDescriptionFromMeta checks if a meta tag is a standard description tag
// and returns its content if present.
func extractDescriptionFromMeta(tokenizer *html.Tokenizer) (string, bool) {
	var name, content string
	for {
		attrKey, attrVal, moreAttr := tokenizer.TagAttr()
		lowAttrKey := strings.ToLower(string(attrKey))

		switch lowAttrKey {
		case "name":
			name = strings.ToLower(string(attrVal))
		case "content":
			content = string(attrVal)
		}

		if!moreAttr {
			break
		}
	}

	// Match standard meta description tag (case-insensitive name)
	if name == "description" && content!= "" {
		return content, true
	}

	return "", false
}

