// isRestrictedIP checks if an IP address belongs to a restricted network range
func isRestrictedIP(ip net.IP) bool {
	// Quick checks for common restricted IP types
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsMulticast() {
		return true
	}

	// Check against all predefined restricted networks
	for _, network := range restrictedNetworks {
		if network.Contains(ip) {
			return true
		}
	}
	return false
}

// customDial validates target IP/port before establishing a connection (prevents SSRF and port scanning)
func customDial(addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err!= nil {
		return nil, fmt.Errorf("invalid address: %w", err)
	}

	// Restrict to standard HTTP/HTTPS ports only
	if port!= "80" && port!= "443" {
		return nil, fmt.Errorf("disallowed port: %s", port)
	}

	// Resolve host to all IP addresses
	ips, err := net.LookupIP(host)
	if err!= nil {
		return nil, fmt.Errorf("failed to resolve host: %w", err)
	}

	// Filter out restricted IPs to prevent internal network access
	var allowedIPs []net.IP
	for _, ip := range ips {
		if!isRestrictedIP(ip) {
			allowedIPs = append(allowedIPs, ip)
		}
	}

	if len(allowedIPs) == 0 {
		return nil, fmt.Errorf("no public IP addresses found for host: %s", host)
	}

	// Try to dial each allowed IP until successful connection
	var lastErr error
	for _, ip := range allowedIPs {
		dialAddr := net.JoinHostPort(ip.String(), port)
		conn, err := fasthttp.Dial(dialAddr) // Uses default 3s dial timeout
		if err == nil {
			return conn, nil
		}
		lastErr = err
	}

	return nil, fmt.Errorf("failed to connect to any allowed IP: %w", lastErr)
}

