			return nil
		}
		ipBytes[0] = byte(nums[0] >> 24)
		ipBytes[1] = byte((nums[0] >> 16) & 0xFF)
		ipBytes[2] = byte((nums[0] >> 8) & 0xFF)
		ipBytes[3] = byte(nums[0] & 0xFF)
	default:
		return nil
	}

	return net.IPv4(ipBytes[0], ipBytes[1], ipBytes[2], ipBytes[3]).To4()
}

// isIPBlocked checks if an IP address is in a blocked/reserved range
func isIPBlocked(ip net.IP) bool {
	// Convert IPv4-mapped IPv6 to IPv4 for checking
	if ipv4 := ip.To4(); ipv4 != nil {
		ip = ipv4
	}

	for _, ipNet := range blockedCIDRs {
		if ipNet.Contains(ip) {
			return true
		}
	}

	return false
}

// validateURL parses and validates a URL for SSRF protection:
// - Checks scheme is http/https
// - Resolves hostname to IPs (or parses if host is an IP)
// - Verifies no IPs are in blocked ranges
// Returns the parsed URL, a valid public IP, port, or error
func validateURL(urlStr string) (*url.URL, net.IP, string, error) {
	parsedURL, err := url.Parse(urlStr)
	if err != nil {
		return nil, nil, "", fmt.Errorf("invalid URL format: %w", err)
	}

	// Only allow http and https schemes
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return nil, nil, "", fmt.Errorf("disallowed scheme %q: only http and https are permitted", parsedURL.Scheme)
	}

	host := parsedURL.Hostname()
	port := parsedURL.Port()

	// Set default port if not present
	if port == "" {
		if parsedURL.Scheme == "http" {
			port = "80"
		} else {
			port = "443"
		}
	}

	// Check if host is an IP address (any format)
	var ips []net.IP
	if ip := parseIPAnyFormat(host); ip != nil {
		ips = []net.IP{ip}
	} else {
		// Resolve hostname to IP addresses
		resolvedIPs, err := net.LookupIP(host)
		if err != nil {
			return nil, nil, "", fmt.Errorf("failed to resolve hostname %q: %w", host, err)
		}
		ips = resolvedIPs
	}

	// Check all IPs are not blocked
	var validIP net.IP
	for _, ip := range ips {
		if isIPBlocked(ip) {
			return nil, nil, "", fmt.Errorf("URL resolves to blocked IP address %q", ip.String())
		}
		// Use the first valid IP (all are public)
		if validIP == nil {
			validIP = ip
		}
	}

	if validIP == nil {
		return nil, nil, "", fmt.Errorf("no valid public IP addresses found for host %q", host)
	}

	return parsedURL, validIP, port, nil
}

const maxRedirects = 10

