		statusCode := currentResp.StatusCode()
		if statusCode < 300 || statusCode >= 400 {
			// Not a redirect, keep the response and exit loop
			httpResp = currentResp
			break
		}

		// Process redirect
		location := string(currentResp.Header.Peek("Location"))
		if location == "" {
			fasthttp.ReleaseResponse(currentResp)
			ctx.SetStatusCode(fasthttp.StatusBadRequest)
			sendJSONResponse(ctx, PreviewResponse{Error: "redirect response with empty Location header"})
			return
		}

		// Resolve relative Location to absolute URL
		newURL, err := parsedURL.Parse(location)
		if err != nil {
			fasthttp.ReleaseResponse(currentResp)
			ctx.SetStatusCode(fasthttp.StatusBadRequest)
			sendJSONResponse(ctx, PreviewResponse{Error: "invalid redirect URL: " + err.Error()})
			return
		}

		// Release response for this redirect iteration
		fasthttp.ReleaseResponse(currentResp)
		currentURL = newURL.String()
	}

