	if httpResp == nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		sendJSONResponse(ctx, PreviewResponse{Error: "too many redirects (max 10 allowed)"})
		return
	}
	defer fasthttp.ReleaseResponse(httpResp)

