	doc, err := goquery.NewDocumentFromReader(httpResp.BodyStream())
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		sendJSONResponse(ctx, PreviewResponse{Error: "failed to parse HTML content: " + err.Error()})
		return
	}

