// sendJSONResponse helper to send properly formatted JSON responses
func sendJSONResponse(ctx *fasthttp.RequestCtx, resp PreviewResponse) {
	ctx.SetContentType("application/json; charset=utf-8")
	data, err := json.Marshal(resp)
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.SetBodyString(`{"error":"failed to encode response data"}`)
