)

const maxBodySize = 1 << 20 // 1MB (1048576 bytes)

// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// Reusable HTTP client with connection pooling and timeouts
var httpClient = &fasthttp.Client{
	Dial:                fasthttp.DialDualStack,
	ReadTimeout:         10 * time.Second,
	WriteTimeout:        10 * time.Second,
	MaxIdleConnDuration: 10 * time.Second,
	MaxConnsPerHost:     10,
	MaxResponseBodySize: maxBodySize,
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST method
	if!ctx.IsPost() {
		ctx.Response.Header.Set("Allow", "POST")
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err!= nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL format and scheme
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err!= nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme!= "http" && parsedURL.Scheme!= "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// Acquire request and response objects from pool
	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod(fasthttp.MethodGet)
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	const maxRedirectCounts = 10
	if err := httpClient.DoRedirects(freq, res, maxRedirectCounts); err!= nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode()!= fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	// Verify response is HTML
	contentType := string(res.Header.ContentType())
	mediaType, _, err := mime.ParseMediaType(contentType)
	if err!= nil || mediaType!= "text/html" {
		ctx.Error("URL does not return HTML content", fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	// Convert response body to UTF-8 to support non-UTF-8 encodings
	bodyReader, err := charset.NewReader(bytes.NewReader(bodyBytes), contentType)
	if err!= nil {
		// Fallback to original body if charset detection fails
		bodyReader = bytes.NewReader(bodyBytes)
	}

	title, description, err := parseHTMLPreview(bodyReader)
	if err!= nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	ctx.SetStatusCode(fasthttp.StatusOK)
	if err := json.NewEncoder(ctx).Encode(resp); err!= nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// parseHTMLPreview extracts title and meta description from HTML.
// It stops parsing once the </head> tag is encountered for efficiency.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	tokenizer := html.NewTokenizer(r)
	inTitle := false
	var titleBuilder strings.Builder

	for {
		tokenType := tokenizer.Next()
		switch tokenType {
		case html.ErrorToken:
			tokenErr := tokenizer.Err()
			if tokenErr == io.EOF {
				// End of document, return collected values
				return strings.TrimSpace(titleBuilder.String()), strings.TrimSpace(description), nil
			}
			// Return actual parsing error
			return "", "", tokenErr
		case html.StartTagToken, html.SelfClosingTagToken:
			tagName, hasAttr := tokenizer.TagName()
			tagStr := strings.ToLower(string(tagName))
			switch tagStr {
			case "title":
				inTitle = true
				titleBuilder.Reset() // Reset for multiple title tags
			case "meta":
				var name, property, content string
				for hasAttr {
					key, val, hasMore := tokenizer.TagAttr()
					attrKey := strings.ToLower(string(key))
					switch attrKey {
					case "name":
						name = strings.ToLower(string(val))
					case "property":
						property = strings.ToLower(string(val))
					case "content":
						content = string(val)
					}
					hasAttr = hasMore
				}
				// Prioritize standard description over Open Graph description
				if name == "description" && content!= "" {
					description = content
				} else if property == "og:description" && content!= "" && description == "" {
					description = content
				}
			}
		case html.EndTagToken:
			tagName, _ := tokenizer.TagName()
			tagStr := strings.ToLower(string(tagName))
			switch tagStr {
			case "title":
				inTitle = false
			case "head":
				// Exit early after head is parsed, no need to process body
				return strings.TrimSpace(titleBuilder.String()), strings.TrimSpace(description), nil
			}
		case html.TextToken:
			if inTitle {
				titleBuilder.Write(tokenizer.Text())
			}
		}
	}
}

