// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// Global HTTP client for connection reuse across requests
var httpClient = &fasthttp.Client{
	Dial:                fasthttp.DialDualStack,
	ReadTimeout:         10 * time.Second,
	WriteTimeout:        10 * time.Second,
	MaxIdleConnDuration: 30 * time.Second,
	MaxConnsPerHost:     100,
	MaxResponseBodySize: 1 << 20, // 1MB limit to prevent OOM from large responses
}

// sendJSONError sends a JSON-formatted error response with the specified status code.
func sendJSONError(ctx *fasthttp.RequestCtx, message string, statusCode int) {
	resp := PreviewResponse{
		Error: message,
	}
	ctx.SetStatusCode(statusCode)
	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		// Fallback to plain text if JSON encoding fails unexpectedly
		ctx.Error("Failed to encode error response", fasthttp.StatusInternalServerError)
	}
}

// FetchURLPreview handles POST requests to fetch URL preview metadata.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST method
	if !ctx.IsPost() {
		sendJSONError(ctx, "Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	// Parse request JSON body
	var req struct {
		URL string `json:"url"`
	}
	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		sendJSONError(ctx, "Invalid JSON request body", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL presence
	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		sendJSONError(ctx, "URL field is required", fasthttp.StatusBadRequest)
		return
	}

	// Parse and validate URL format
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		sendJSONError(ctx, "Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	// Enforce HTTP/HTTPS scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		sendJSONError(ctx, "URL must use HTTP or HTTPS scheme", fasthttp.StatusBadRequest)
		return
	}

	// Acquire request/response objects from pool to reduce allocations
	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	// Configure outgoing request
	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod(fasthttp.MethodGet)
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0 (+https://example.com/bot)")

	// Execute request with redirect following
	const maxRedirects = 10
	if err := httpClient.DoRedirects(freq, res, maxRedirects); err != nil {
		sendJSONError(ctx, fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	// Validate successful response status
	if res.StatusCode() != fasthttp.StatusOK {
		sendJSONError(ctx, fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	// Verify response is HTML
	contentType := string(res.Header.ContentType())
	if !strings.HasPrefix(strings.ToLower(contentType), "text/html") {
		sendJSONError(ctx, "URL does not return HTML content", fasthttp.StatusBadGateway)
		return
	}

	// Check for empty response body
	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		sendJSONError(ctx, "Empty response body from URL", fasthttp.StatusBadGateway)
		return
	}

	// Convert HTML to UTF-8 to handle non-UTF-8 encodings
	utf8Reader, err := charset.NewReader(bytes.NewReader(bodyBytes), contentType)
	if err != nil {
		sendJSONError(ctx, fmt.Sprintf("Failed to decode HTML encoding: %v", err), fasthttp.StatusBadGateway)
		return
	}

	// Extract title and description from HTML
	title, description, err := parseHTMLPreview(utf8Reader)
	if err != nil {
		sendJSONError(ctx, fmt.Sprintf("Failed to parse HTML content: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	// Prepare and send successful response
	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}
	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		sendJSONError(ctx, "Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// parseHTMLPreview extracts title and meta description from HTML content.
// Stops parsing early after </head> tag or when both fields are found for efficiency.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	tokenizer := html.NewTokenizer(r)
	inTitle := false
	var titleBuf strings.Builder

	for {
		tokenType := tokenizer.Next()
		switch tokenType {
		case html.ErrorToken:
			// Handle end of input or parsing errors
			err = tokenizer.Err()
			if err == io.EOF {
				err = nil // EOF is expected, not an actual error
			}
			return strings.TrimSpace(titleBuf.String()), strings.TrimSpace(description), err

		case html.StartTagToken, html.SelfClosingTagToken:
			tagName, hasAttr := tokenizer.TagName()
			tag := string(tagName)

			switch tag {
			case "title":
				inTitle = true
				titleBuf.Reset()
				continue
			case "meta":
				var name, content string
				for hasAttr {
					var key, val []byte
					key, val, hasAttr = tokenizer.TagAttr()
					attrKey := string(key)
					attrVal := string(val)

					switch attrKey {
					case "name":
						// Case-insensitive match for description meta tag
						if strings.EqualFold(attrVal, "description") {
							name = attrVal
						}
					case "content":
						content = attrVal
					}
				}
				if name != "" {
					description = content
				}
			}

		case html.TextToken:
			// Collect all text content inside title tag
			if inTitle {
				titleBuf.Write(tokenizer.Text())
			}

		case html.EndTagToken:
			tagName, _ := tokenizer.TagName()
			tag := string(tagName)

			switch tag {
			case "head":
				// Exit early once head is parsed (metadata is only in head)
				return strings.TrimSpace(titleBuf.String()), strings.TrimSpace(description), nil
			case "title":
				inTitle = false
			}
		}

		// Early exit if we have both required fields
		if titleBuf.Len() > 0 && description != "" {
			return strings.TrimSpace(titleBuf.String()), strings.TrimSpace(description), nil
		}
	}
}

func main() {
	log.Println("URL Preview server starting on :8080")
	log.Println("Usage: POST / with JSON body {\"url\": \"https://example.com\"}")
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err != nil {
		log.Fatalf("Failed to start server: %v", err)
	}
}

