// safeDial validates IP addresses before connecting to prevent SSRF and DNS rebinding
func safeDial(addr string) (net.Conn, error) {
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	host, portStr, err := net.SplitHostPort(addr)
	if err!= nil {
		return nil, fmt.Errorf("invalid address: %w", err)
	}

	// Resolve host to IP addresses first
	ipAddrs, err := net.DefaultResolver.LookupIPAddr(ctx, host)
	if err!= nil {
		return nil, fmt.Errorf("failed to resolve host %s: %w", host, err)
	}

	// Resolve port number
	port, err := net.LookupPort("tcp", portStr)
	if err!= nil {
		return nil, fmt.Errorf("invalid port %s: %w", portStr, err)
	}

	// Build TCP addresses from resolved IPs and port
	var tcpAddrs []*net.TCPAddr
	for _, ipAddr := range ipAddrs {
		tcpAddrs = append(tcpAddrs, &net.TCPAddr{
			IP:   ipAddr.IP,
			Port: port,
			Zone: ipAddr.Zone,
		})
	}

	// Validate all resolved IPs are not restricted
	for _, tcpAddr := range tcpAddrs {
		if isIPRestricted(tcpAddr.IP) {
			return nil, &ValidationError{Msg: "Requested URL is not allowed"}
		}
	}

	// Dial validated IP addresses directly to prevent DNS rebinding
	dialer := net.Dialer{
		Timeout: 5 * time.Second,
	}
	var conn net.Conn
	var lastErr error
	for _, tcpAddr := range tcpAddrs {
		conn, err = dialer.DialContext(ctx, "tcp", tcpAddr.String())
		if err == nil {
			return conn, nil
		}
		lastErr = err
	}

	return nil, fmt.Errorf("failed to connect: %w", lastErr)
}

